+async function buildBrowserStatus(req: BrowserRequest, ctx: BrowserRouteContext) {
+  let current: ReturnType<typeof ctx.state>;
+  try {
+    current = ctx.state();
+  } catch {
+    throw new BrowserError("browser server not started", 503);
+  }
